import React from 'react';
import { Link } from 'react-router-dom';
import bcLogo from '../../assets/portfolio/bc_logo.svg';
import inWaysLogo from '../../assets/portfolio/innovativeways_logo.svg';
import tutorPlaceLogo from '../../assets/portfolio/tutorPlace_logo.svg';
import willSkillLogo from '../../assets/portfolio/willskill_logo.svg';
import s from './style.module.scss';

const projects = [
  {
    id: 1,
    title: 'Business Control',
    img: bcLogo,
  },
  {
    id: 2,
    title: 'Innovative Ways',
    link: 'https://innovativeways.net',
    img: inWaysLogo,
  },
  {
    id: 3,
    title: 'WillSkill',
    link: 'https://willskill.ru',
    img: willSkillLogo,
  },
  {
    id: 4,
    title: 'TutorPlace',
    link: 'https://tutorplace.ru',
    img: tutorPlaceLogo,
  },
];

const Portfolio = () => {
  return (
    <div className={s.container}>
      {projects.map((project) => (
        <div
          target='_blank'
          to={project.link}
          title={project.title}
          key={project.id}
          className={s.itemBlock}
          onClick={(e) => !project.link && e.preventDefault()}
        >
          <img src={project.img} alt={project.title} />
          <Link to={project.link} data-local={!project.link}>
            {project.link ? 'See Live' : 'Local project'}
          </Link>
        </div>
      ))}
    </div>
  );
};

export default Portfolio;
